final class UniversalLinkHandler {
    
    // Strict allowlist of accepted hosts
    private static let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    // Strict allowlist of accepted path prefixes
    private static let allowedPathPrefixes: [String] = [
        "/profile/",
        "/payment/confirm",
        "/admin/settings"
    ]
    
    // Maximum allowed URL length to prevent abuse
    private static let maxURLLength = 2048
    
    // Maximum allowed path component length
    private static let maxPathComponentLength = 128
    
    // MARK: - URL Validation
    
    /// Validates that the URL is a legitimate universal link for our app.
    static func isValidUniversalLink(_ url: URL) -> Bool {
        // 1. Enforce maximum URL length
        guard url.absoluteString.count <= maxURLLength else {
            logSecurityEvent("URL exceeds maximum length: \(url.absoluteString.prefix(100))...")
            return false
        }
        
        // 2. Enforce HTTPS only
        guard url.scheme?.lowercased() == "https" else {
            logSecurityEvent("Rejected non-HTTPS scheme: \(url.scheme ?? "nil")")
            return false
        }
        
        // 3. Validate host against strict allowlist
        guard let host = url.host?.lowercased(), allowedHosts.contains(host) else {
            logSecurityEvent("Rejected unknown host: \(url.host ?? "nil")")
            return false
        }
        
        // 4. Normalize path and check for path traversal attacks
        let path = url.path
        guard !path.contains("..") && !path.contains("//") else {
            logSecurityEvent("Rejected path traversal attempt: \(path)")
            return false
        }
        
        // 5. Validate path against allowlist prefixes
        let matchesAllowedPath = allowedPathPrefixes.contains { prefix in
            path.lowercased().hasPrefix(prefix.lowercased())
        }
        guard matchesAllowedPath else {
            logSecurityEvent("Rejected unknown path: \(path)")
            return false
        }
        
        // 6. Validate individual path components are not excessively long
        let components = path.split(separator: "/")
        for component in components {
            guard component.count <= maxPathComponentLength else {
                logSecurityEvent("Path component exceeds max length")
                return false
            }
        }
        
        return true
    }
    
    // MARK: - Route Parsing
    
    /// Parses a validated URL into a typed route.
    static func parseRoute(from url: URL) -> DeepLinkRoute {
        guard isValidUniversalLink(url) else {
            return .unknown
        }
        
        let path = url.path.lowercased()
        let pathComponents = path
            .split(separator: "/")
            .map(String.init)
        
        // Match routes explicitly
        switch pathComponents.count {
        case 2 where pathComponents[0] == "profile":
            let rawUserID = pathComponents[1]
            // Validate userID: must be alphanumeric, reasonable length
            guard isValidUserID(rawUserID) else {
                logSecurityEvent("Invalid user ID format: \(rawUserID.prefix(20))")
                return .unknown
            }
            return .profile(userID: rawUserID)
            
        case 2 where pathComponents[0] == "payment" && pathComponents[1] == "confirm":
            return .paymentConfirm
            
        case 2 where pathComponents[0] == "admin" && pathComponents[1] == "settings":
            return .adminSettings
            
        default:
            logSecurityEvent("No route matched for path: \(path)")
            return .unknown
        }
    }
    
    // MARK: - Parameter Validation
    
    /// Validates that a user ID contains only safe characters and is within bounds.
    private static func isValidUserID(_ userID: String) -> Bool {
        // Only allow alphanumeric characters and hyphens (for UUIDs)
        let allowedCharacterSet = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-"))
        guard userID.unicodeScalars.allSatisfy({ allowedCharacterSet.contains($0) }) else {
            return false
        }
        // Enforce reasonable length (1-64 characters)
        guard (1...64).contains(userID.count) else {
