// MARK: - Authorization Service

protocol AuthorizationServiceProtocol {
    func isUserAuthenticated() -> Bool
    func isUserAdmin() -> Bool
    func currentUserID() -> String?
    func canAccessProfile(userID: String) -> Bool
}

final class AuthorizationService: AuthorizationServiceProtocol {
    static let shared = AuthorizationService()
    
    private init() {}
    
    func isUserAuthenticated() -> Bool {
        // Replace with actual authentication check
        // e.g., check for valid session token, JWT expiry, etc.
        return SessionManager.shared.isAuthenticated
    }
    
    func isUserAdmin() -> Bool {
        guard isUserAuthenticated() else { return false }
        return SessionManager.shared.currentUserRole == .admin
    }
    
    func currentUserID() -> String? {
        return SessionManager.shared.currentUserID
    }
    
    func canAccessProfile(userID: String) -> Bool {
        guard isUserAuthenticated() else { return false }
        // Users can view their own profile; admins can view any profile
        return currentUserID() == userID || isUserAdmin()
    }
}

