// MARK: - Navigation Coordinator

protocol NavigationCoordinatorProtocol {
    func navigateToProfile(userID: String)
    func navigateToPaymentConfirm()
    func navigateToAdminSettings()
    func navigateToLogin(pendingRoute: DeepLinkRoute?)
    func navigateToAccessDenied()
    func navigateToNotFound()
}

final class NavigationCoordinator: NavigationCoordinatorProtocol {
    
    private weak var window: UIWindow?
    
    init(window: UIWindow?) {
        self.window = window
    }
    
    private var rootNavigationController: UINavigationController? {
        return window?.rootViewController as? UINavigationController
    }
    
    func navigateToProfile(userID: String) {
        let profileVC = ProfileViewController()
        profileVC.userID = userID
        rootNavigationController?.pushViewController(profileVC, animated: true)
    }
    
    func navigateToPaymentConfirm() {
        let paymentVC = PaymentConfirmViewController()
        rootNavigationController?.pushViewController(paymentVC, animated: true)
    }
    
    func navigateToAdminSettings() {
        let adminVC = AdminSettingsViewController()
        rootNavigationController?.pushViewController(adminVC, animated: true)
    }
    
    func navigateToLogin(pendingRoute: DeepLinkRoute?) {
        let loginVC = LoginViewController()
        loginVC.pendingDeepLinkRoute = pendingRoute
        rootNavigationController?.pushViewController(loginVC, animated: true)
    }
    
    func navigateToAccessDenied() {
        let accessDeniedVC = AccessDeniedViewController()
        rootNavigationController?.pushViewController(accessDeniedVC, animated: true)
    }
    
    func navigateToNotFound() {
        let notFoundVC = NotFoundViewController()
        rootNavigationController?.pushViewController(notFoundVC, animated: true)
    }
}

// MARK: - Deep Link Router (Orchestrates validation, authorization, and navigation)

final class DeepLinkRouter {
    
    private let authService: AuthorizationServiceProtocol
    private let navigator: NavigationCoordinatorProtocol
    
    init(authService: AuthorizationServiceProtocol, navigator: NavigationCoordinatorProtocol) {
        self.authService = authService
        self.navigator = navigator
    }
    
    /// Main entry point: handles a universal link end-to-end.
    func handleUniversalLink(_ url: URL) -> Bool {
        // Step 1: Parse and validate the URL
        let route = UniversalLinkHandler.parseRoute(from: url)
        
        guard route != .unknown else {
            navigator.navigateToNotFound()
            return false
        }
        
        // Step 2: Perform authorization checks per route
        return authorizeAndNavigate(route: route)
    }
    
    /// Checks authorization for the given route and navigates accordingly.
    private func authorizeAndNavigate(route: DeepLinkRoute) -> Bool {
        switch route {
            
        case .profile(let userID):
            // Profile requires authentication
            guard authService.isUserAuthenticated() else {
                navigator.navigateToLogin(pendingRoute: route)
                return true
            }
            // Authorization: user can only access their own profile (or admin can access any)
            guard authService.canAccessProfile(userID: userID) else {
                logAuthorizationFailure(route: route)
                navigator.navigateToAccessDenied()
                return false
            }
            navigator.navigateToProfile(userID: userID)
            return true
            
        case .paymentConfirm:
            // Payment confirmation requires authentication
            guard authService.isUserAuthenticated() else {
                navigator.navigateToLogin(pendingRoute: route)
                return true
            }
            navigator.navigateToPaymentConfirm()
            return true
            
        case .adminSettings:
            // Admin settings requires authentication AND admin role
            guard authService.isUserAuthenticated() else {
                navigator.navigateToLogin(pendingRoute: route)
                return true
            }
            guard authService.isUserAdmin() else {
                logAuthorizationFailure(route: route)
                navigator.navigateToAccessDenied()
                return false
            }
            navigator.navigateToAdminSettings()
            return true
            
        case .unknown:
            navigator.navigateToNotFound()
            return false
        }
    }
    
    private func logAuthorizationFailure(route: DeepLinkRoute) {
        let userID = authService.currentUserID() ?? "unknown"
        #if DEBUG
        print("[DeepLinkRouter] Authorization denied for user \(userID) accessing route: \(route)")
        #endif
        // TODO: Log to security monitoring in production
    }
}

