        let navigator = NavigationCoordinator(window: window)
        let authService = AuthorizationService.shared
        deepLinkRouter = DeepLinkRouter(authService: authService, navigator: navigator)
        
        return true
    }
    
    // MARK: - Universal Link Handling
    
    func application(
        _ application: UIApplication,
        continue userActivity: NSUserActivity,
        restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void
    ) -> Bool {
        
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return deepLinkRouter?.handleUniversalLink(url) ?? false
    }
}

// MARK: - SceneDelegate Integration (iOS 13+)

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var deepLinkRouter: DeepLinkRouter?
    
    func scene(
        _ scene: UIScene,
        willConnectTo session: UISceneSession,
        options connectionOptions: UIScene.ConnectionOptions
    ) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        window = UIWindow(windowScene: windowScene)
        let rootVC = UINavigationController(rootViewController: HomeViewController())
        window?.rootViewController = rootVC
        window?.makeKeyAndVisible()
        
        let navigator = NavigationCoordinator(window: window)
        let authService = AuthorizationService.shared
        deepLinkRouter = DeepLinkRouter(authService: authService, navigator: navigator)
        
        // Handle universal links that arrived at launch
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            _ = deepLinkRouter?.handleUniversalLink(url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        _ = deepLinkRouter?.handleUniversalLink(url)
    }
}

